class AuthorizationResult:
    """Represents the result of an authorization decision."""

    def __init__(
        self,
        allowed: bool,
        http_status_code: int = 200,
        message: str = "",
        headers_to_add: Optional[Dict[str, str]] = None,
        headers_to_remove: Optional[List[str]] = None,
        identity: Optional[Dict] = None,
    ):
        self.allowed = allowed
        self.http_status_code = http_status_code
        self.message = message
        self.headers_to_add = headers_to_add or {}
        self.headers_to_remove = headers_to_remove or []
        self.identity = identity or {}


class EnvoyExternalAuthServicer:
    """
    gRPC servicer that implements the Envoy ext_authz Check API.

    This can work with both the generated protobuf classes and a manual
    implementation for environments where the Envoy protos aren't available.
    """

    def __init__(self, policy: Optional[AuthorizationPolicy] = None):
        self.policy = policy or AuthorizationPolicy()
        logger.info("Envoy External Authorization Service initialized")

    def evaluate_request(
        self,
        headers: Dict[str, str],
        path: str,
        method: str,
        source_ip: str,
        protocol: str,
    ) -> AuthorizationResult:
        """
        Core authorization logic. Evaluates the request and returns a decision.

        Args:
            headers: HTTP headers from the request
            path: Request path
            method: HTTP method
            source_ip: Source IP address
            protocol: Protocol (HTTP/1.1, HTTP/2, etc.)

        Returns:
            AuthorizationResult with the decision
        """
        logger.info(
            f"Evaluating request: method={method} path={path} "
            f"source_ip={source_ip} protocol={protocol}"
        )

        # 1. Check IP blocklist/allowlist
        if not self.policy.is_ip_allowed(source_ip):
            logger.warning(f"IP {source_ip} is blocked")
            return AuthorizationResult(
                allowed=False,
                http_status_code=403,
                message="Forbidden: IP address not allowed",
            )

        # 2. Check if path is blocked
        if self.policy.is_blocked_path(path):
            logger.warning(f"Blocked path accessed: {path}")
            return AuthorizationResult(
                allowed=False,
                http_status_code=403,
                message="Forbidden: Path is not accessible",
            )

        # 3. Check if path is public
        if self.policy.is_public_path(path):
            logger.info(f"Public path accessed: {path}")
            return AuthorizationResult(
                allowed=True,
                headers_to_add={
                    "x-auth-status": "public",
                    "x-auth-service": "envoy-ext-authz",
                },
            )

        # 4. Check required headers for specific paths
        header_error = self.policy.check_required_headers(path, headers)
        if header_error:
            logger.warning(f"Missing required header: {header_error}")
            return AuthorizationResult(
                allowed=False,
                http_status_code=400,
                message=header_error,
            )

        # 5. Extract and validate credentials
        identity = None
        auth_method = None

        # Check for API key in header
        api_key = headers.get("x-api-key", "")
        if api_key:
            identity = self.policy.validate_api_key(api_key)
            auth_method = "api-key"

        # Check for Bearer token in Authorization header
        if not identity:
            auth_header = headers.get("authorization", "")
            if auth_header.startswith("Bearer "):
                token = auth_header[7:]
                identity = self.policy.validate_bearer_token(token)
                auth_method = "bearer-token"

        # Check for custom auth header
        if not identity:
            custom_auth = headers.get("x-custom-auth-token", "")
            if custom_auth:
                # Custom auth logic - could call external service, database, etc.
                identity = self.policy.validate_api_key(custom_auth)
                auth_method = "custom-token"

        # 6. No valid credentials found
        if not identity:
            logger.warning(f"No valid credentials for {method} {path}")
            return AuthorizationResult(
                allowed=False,
                http_status_code=401,
                message="Unauthorized: No valid credentials provided",
                headers_to_add={
                    "www-authenticate": 'Bearer realm="envoy-ext-authz"',
                },
            )

        # 7. Check path and method permissions
        if not self.policy.check_path_permission(identity, path, method):
            logger.warning(
                f"Permission denied for {identity['name']}: {method} {path}"
            )
            return AuthorizationResult(
                allowed=False,
                http_status_code=403,
                message=f"Forbidden: Insufficient permissions for {method} {path}",
                identity=identity,
            )

        # 8. Check rate limiting
        rate_limit = identity.get("rate_limit", 0)
        if rate_limit > 0 and not self.policy.check_rate_limit(
            identity["name"], rate_limit
        ):
            logger.warning(f"Rate limit exceeded for {identity['name']}")
            return AuthorizationResult(
                allowed=False,
                http_status_code=429,
                message="Too Many Requests: Rate limit exceeded",
                headers_to_add={
                    "retry-after": "60",
                    "x-ratelimit-limit": str(rate_limit),
                    "x-ratelimit-remaining": "0",
                },
                identity=identity,
            )

        # 9. Authorization successful
        logger.info(
            f"Authorized: {identity['name']} ({auth_method}) -> {method} {path}"
        )
        return AuthorizationResult(
            allowed=True,
            headers_to_add={
                "x-auth-status": "authenticated",
                "x-auth-identity": identity["name"],
                "x-auth-roles": ",".join(identity.get("roles", [])),
                "x-auth-method": auth_method,
                "x-auth-service": "envoy-ext-authz",
            },
            headers_to_remove=[
                "x-api-key",  # Don't forward API keys to upstream
                "x-custom-auth-token",
            ],
            identity=identity,
        )


