# Inline proto definitions for when external packages aren't available
EXTERNAL_AUTH_PROTO = """
syntax = "proto3";

package envoy.service.auth.v3;

import "google/rpc/status.proto";

service Authorization {
  rpc Check(CheckRequest) returns (CheckResponse) {}
}

message CheckRequest {
  AttributeContext attributes = 1;
}

message CheckResponse {
  google.rpc.Status status = 1;
  oneof http_response {
    DeniedHttpResponse denied_response = 2;
    OkHttpResponse ok_response = 3;
  }
}

message AttributeContext {
  message Peer {
    Address address = 1;
    string principal = 2;
  }

  message Request {
    HttpRequest http = 2;
  }

  message HttpRequest {
    string method = 1;
    map<string, string> headers = 2;
    string path = 3;
    string host = 4;
    string scheme = 5;
    string protocol = 9;
  }

  Peer source = 1;
  Peer destination = 2;
  Request request = 4;
}

message Address {
  SocketAddress socket_address = 1;
}

message SocketAddress {
  string address = 1;
  uint32 port_value = 2;
}

message DeniedHttpResponse {
  HttpStatus status = 1;
  repeated HeaderValueOption headers = 2;
  string body = 3;
}

message OkHttpResponse {
  repeated HeaderValueOption headers = 2;
  repeated string headers_to_remove = 5;
}

message HeaderValueOption {
  HeaderValue header = 1;
}

message HeaderValue {
  string key = 1;
  string value = 2;
}

message HttpStatus {
  int32 code = 1;
}
"""


def compile_protos_inline():
    """
    Compile proto definitions inline for self-contained operation.
    Returns generated modules or None if compilation fails.
    """
    try:
        import tempfile
        import subprocess
        import importlib.util

        proto_dir = tempfile.mkdtemp(prefix="envoy_auth_")
        proto_file = os.path.join(proto_dir, "external_auth.proto")

        # Write proto file
        with open(proto_file, "w") as f:
            f.write(EXTERNAL_AUTH_PROTO)

        # Also need google/rpc/status.proto
        google_rpc_dir = os.path.join(proto_dir, "google", "rpc")
        os.makedirs(google_rpc_dir, exist_ok=True)

        status_proto = """
syntax = "proto3";
package google.rpc;

message Status {
  int32 code = 1;
  string message = 2;
}
"""
        with open(os.path.join(google_rpc_dir, "status.proto"), "w") as f:
            f.write(status_proto)

        # Compile with grpc_tools
        from grpc_tools import protoc

        result = protoc.main([
            "grpc_tools.protoc",
            f"--proto_path={proto_dir}",
            f"--python_out={proto_dir}",
            f"--grpc_python_out={proto_dir}",
            proto_file,
            os.path.join(google_rpc_dir, "status.proto"),
        ])

        if result != 0:
            logger.error("Proto compilation failed")
            return None

        # Import the generated modules
        sys.path.insert(0, proto_dir)
        import external_auth_pb2 as ea_pb2
        import external_auth_pb2_grpc as ea_pb2_grpc
        from google.rpc import status_pb2 as s_pb2

        return ea_pb2, ea_pb2_grpc, s_pb2

    except Exception as e:
        logger.error(f"Failed to compile protos inline: {e}")
        return None


