class SelfContainedAuthServicer:
    """
    Self-contained auth servicer that compiles its own protobuf definitions.
    Used as a fallback when envoy-data-plane package isn't installed.
    """

    def __init__(self, pb2, pb2_grpc, status_pb2, policy=None):
        self.pb2 = pb2
        self.pb2_grpc = pb2_grpc
        self.status_pb2 = status_pb2
        self.auth_service = EnvoyExternalAuthServicer(policy)

    def Check(self, request, context):
        """Handle the Check RPC."""
        try:
            # Extract attributes from the request
            attrs = request.attributes
            http_attrs = attrs.request.http

            headers = dict(http_attrs.headers)
            path = http_attrs.path
            method = http_attrs.method
            protocol = http_attrs.protocol

            # Extract source IP
            source_ip = ""
            if attrs.source and attrs.source.address:
                source_ip = attrs.source.address.socket_address.address

            forwarded_for = headers.get("x-forwarded-for", "")
            if forwarded_for:
                source_ip = forwarded_for.split(",")[0].strip()

            # Evaluate
            result = self.auth_service.evaluate_request(
                headers=headers,
                path=path,
                method=method,
                source_ip=source_ip,
                protocol=protocol,
            )

            return self._build_response(result)

        except Exception as e:
            logger.error(f"Error in Check: {e}", exc_info=True)
            result = AuthorizationResult(
                allowed=False,
                http_status_code=500,
                message="Internal authorization error",
            )
            return self._build_response(result)

    def _build_response(self, result: AuthorizationResult):
        """Build response using self-compiled protobuf types."""
        pb2 = self.pb2

        response = pb2.CheckResponse()

        if result.allowed:
            response.status.CopyFrom(
                self.status_pb2.Status(code=0)  # OK
            )

            ok_response = pb2.OkHttpResponse()
            for key, value in result.headers_to_add.items():
                header_opt = pb2.HeaderValueOption(
                    header=pb2.HeaderValue(key=key, value=value)
                )
                ok_response.headers.append(header_opt)

            for header_name in result.headers_to_remove:
                ok_response.headers_to_remove.append(header_name)

            response.ok_response.CopyFrom(ok_response)

        else:
            response.status.CopyFrom(
                self.status_pb2.Status(
                    code=7,  # PERMISSION_DENIED
                    message=result.message,
                )
            )

            denied_response = pb2.DeniedHttpResponse()
            denied_response.status.CopyFrom(
                pb2.HttpStatus(code=result.http_status_code)
            )
            denied_response.body = json.dumps({
                "error": result.message,
                "status": result.http_status_code,
            })

            for key, value in result.headers_to_add.items():
                header_opt = pb2.HeaderValueOption(
                    header=pb2.HeaderValue(key=key, value=value)
                )
                denied_response.headers.append(header_opt)

            ct_header = pb2.HeaderValueOption(
                header=pb2.HeaderValue(
                    key="content-type",
                    value="application/json",
                )
            )
            denied_response.headers.append(ct_header)

            response.denied_response.CopyFrom(denied_response)

        return response


