def create_server(
    port: int = 50051,
    max_workers: int = 10,
    policy: Optional[AuthorizationPolicy] = None,
    enable_reflection: bool = True,
    enable_health_check: bool = True,
) -> grpc.Server:
    """
    Create and configure the gRPC server.

    Args:
        port: Port to listen on
        max_workers: Maximum number of worker threads
        policy: Authorization policy to use
        enable_reflection: Enable gRPC server reflection
        enable_health_check: Enable gRPC health checking

    Returns:
        Configured gRPC server
    """
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        options=[
            ("grpc.max_send_message_length", 50 * 1024 * 1024),
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),
            ("grpc.keepalive_time_ms", 30000),
            ("grpc.keepalive_timeout_ms", 10000),
            ("grpc.keepalive_permit_without_calls", True),
            ("grpc.http2.max_pings_without_data", 0),
            ("grpc.http2.min_time_between_pings_ms", 10000),
        ],
    )

    # Try to use the proper Envoy protobuf servicer first
    service_names = []

    if HAS_ENVOY_PROTOS:
        logger.info("Using official Envoy protobuf definitions")
        servicer = AuthorizationServicer(policy)
        external_auth_pb2_grpc.add_AuthorizationServicer_to_server(servicer, server)
        service_names.append(external_auth_pb2.DESCRIPTOR.services_by_name["Authorization"].full_name)
    else:
        # Try to compile protos inline
        logger.info("Attempting to compile protos inline...")
        compiled = compile_protos_inline()

        if compiled:
            pb2, pb2_grpc, s_pb2 = compiled
            logger.info("Successfully compiled inline protos")
            servicer = SelfContainedAuthServicer(pb2, pb2_grpc, s_pb2, policy)

            # Create a proper servicer class dynamically
            class DynamicAuthServicer(pb2_grpc.AuthorizationServicer):
                def __init__(self, inner_servicer):
                    self._inner = inner_servicer

                def Check(self, request, context):
                    return self._inner.Check(request, context)

            dynamic_servicer = DynamicAuthServicer(servicer)
            pb2_grpc.add_AuthorizationServicer_to_server(dynamic_servicer, server)
            service_names.append("envoy.service.auth.v3.Authorization")
        else:
            logger.error(
                "Cannot start server: no protobuf definitions available. "
                "Install envoy-data-plane or grpcio-tools."
            )
            raise RuntimeError("No protobuf definitions available")

    # Add health check service
    if enable_health_check:
        try:
            health_servicer = HealthServicer()
            health_pb2_grpc.add_HealthServicer_to_server(health_servicer, server)
            health_servicer.set("", health_pb2.HealthCheckResponse.SERVING)
            for sn in service_names:
                health_servicer.set(sn, health_pb2.HealthCheckResponse.SERVING)
            logger.info("Health check service enabled")
        except Exception as e:
            logger.warning(f"Could not enable health check service: {e}")

    # Add server reflection
    if enable_reflection:
        try:
            from grpc_reflection.v1alpha import reflection
            reflection.enable_server_reflection(
                service_names + [reflection.SERVICE_NAME],
                server,
            )
            logger.info("Server reflection enabled")
        except ImportError:
            logger.warning("grpcio-reflection not installed, reflection disabled")

    # Bind to port
    listen_address = f"[::]:{port}"
    server.add_insecure_port(listen_address)
    logger.info(f"Server will listen on {listen_address}")

    return server


def create_secure_server(
    port: int = 50051,
    max_workers: int = 10,
    policy: Optional[AuthorizationPolicy] = None,
    server_cert_path: str = "server.crt",
    server_key_path: str = "server.key",
    ca_cert_path: Optional[str] = None,
) -> grpc.Server:
    """
    Create a TLS-secured gRPC server.

    Args:
        port: Port to listen on
        max_workers: Maximum number of worker threads
        policy: Authorization policy to use
        server_cert_path: Path to server certificate
        server_key_path: Path to server private key
        ca_cert_path: Path to CA certificate for mutual TLS (optional)

    Returns:
        Configured gRPC server with TLS
    """
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
    )

    if HAS_ENVOY_PROTOS:
        servicer = AuthorizationServicer(policy)
        external_auth_pb2_grpc.add_AuthorizationServicer_to_server(servicer, server)

    # Load TLS credentials
    with open(server_key_path, "rb") as f:
        server_key = f.read()
    with open(server_cert_path, "rb") as f:
        server_cert = f.read()

    ca_cert = None
    if ca_cert_path:
        with open(ca_cert_path, "rb") as f:
            ca_cert = f.read()

    credentials = grpc.ssl_server_credentials(
        [(server_key, server_cert)],
        root_certificates=ca_cert,
        require_client_auth=ca_cert is not None,
    )

    listen_address = f"[::]:{port}"
    server.add_secure_port(listen_address, credentials)
    logger.info(f"Secure server will listen on {listen_address}")

    return server


def serve(
    port: int = 50051,
    max_workers: int = 10,
    policy: Optional[AuthorizationPolicy] = None,
):
    """
    Start the gRPC server and block until terminated.

    Args:
        port: Port to listen on
        max_workers: Maximum number of worker threads
        policy: Authorization policy to use
    """
    server = create_server(
        port=port,
        max_workers=max_workers,
        policy=policy,
    )

    server.start()
    logger.info(f"Envoy External Authorization Service started on port {port}")
    logger.info("Press Ctrl+C to stop")

    try:
        while True:
            time.sleep(86400)  # Sleep for a day
    except KeyboardInterrupt:
        logger.info("Shutting down...")
        server.stop(grace=5)
        logger.info("Server stopped")


# ============================================================================
# Test client for verifying the service
# ============================================================================

def test_client(host: str = "localhost", port: int = 50051):
    """
    Test client that sends sample CheckRequests to the auth service.
    """
    channel = grpc.insecure_channel(f"{host}:{port}")

    if HAS_ENVOY_PROTOS:
        stub = external_auth_pb2_grpc.AuthorizationStub(channel)

        test_cases = [
            {
                "name": "Public health endpoint",
                "method": "GET",
                "path": "/health",
                "headers": {},
                "expected_allowed": True,
            },
            {
                "name": "Unauthenticated request to protected endpoint",
                "method": "GET",
                "path": "/api/v1/users",
                "headers": {},
                "expected_allowed": False,
            },
            {
                "name": "Valid API key - admin",
                "method": "GET",
                "path": "/api/v1/users",
                "headers": {"x-api-key": "api-key-admin-001"},
                "expected_allowed": True,
            },
            {
                "name": "Valid API key - reader accessing read endpoint",
                "method": "GET",
                "path": "/api/v1/read/data",
                "headers": {"x-api-key": "api-key-reader-001"},
                "expected_allowed": True,
            },
            {
                "name": "Reader trying to POST (should fail)",
                "method": "POST",
                "path": "/api/v1/write/data",
                "headers": {"x-api-key": "api-key-reader-001"},
                "expected_allowed": False,
            },
            {
                "name": "Valid Bearer token",
                "method": "GET",
                "path": "/api/v1/user/profile",
                "headers": {"authorization": "Bearer bearer-token-user"},
                "expected_allowed": True,
            },
            {
                "name": "Blocked path",
                "method": "GET",
                "path": "/admin/internal/config",
                "headers": {"x-api-key": "api-key-admin-001"},
                "expected_allowed": False,
            },
            {
                "name": "Invalid API key",
                "method": "GET",
                "path": "/api/v1/data",
                "headers": {"x-api-key": "invalid-key"},
                "expected_allowed": False,
            },
        ]

        print("\n" + "=" * 70)
        print("Envoy External Authorization Service - Test Client")
        print("=" * 70)

        for tc in test_cases:
            # Build CheckRequest
            http_request = external_auth_pb2.AttributeContext.HttpRequest(
                method=tc["method"],
                path=tc["path"],
                headers=tc["headers"],
                host="example.com",
                scheme="https",
                protocol="HTTP/2",
            )

            request_ctx = external_auth_pb2.AttributeContext.Request(
                http=http_request,
            )

            source = external_auth_pb2.AttributeContext.Peer(
                address=base_pb2.Address(
                    socket_address=base_pb2.SocketAddress(
                        address="10.0.0.1",
                        port_value=12345,
                    )
                )
            )

            attrs = external_auth_pb2.AttributeContext(
                source=source,
                request=request_ctx,
            )

            check_request = external_auth_pb2.CheckRequest(attributes=attrs)

            try:
                response = stub.Check(check_request, timeout=5)
                is_allowed = response.status.code == 0  # OK

                status = "✅ PASS" if is_allowed == tc["expected_allowed"] else "❌ FAIL"
                result = "ALLOWED" if is_allowed else "DENIED"

                print(f"\n{status} | {tc['name']}")
                print(f"  Request: {tc['method']} {tc['path']}")
                print(f"  Result: {result} (expected: {'ALLOWED' if tc['expected_allowed'] else 'DENIED'})")

                if is_allowed and response.HasField("ok_response"):
                    added_headers = {
                        h.header.key: h.header.value
                        for h in response.ok_response.headers
                    }
                    if added_headers:
                        print(f"  Added headers: {added_headers}")
                elif not is_allowed and response.HasField("denied_response"):
                    print(f"  HTTP Status: {response.denied_response.status.code}")
                    print(f"  Message: {response.status.message}")

            except grpc.RpcError as e:
                print(f"\n❌ ERROR | {tc['name']}: {e}")

        print("\n" + "=" * 70)
        print("Test complete")
        print("=" * 70)

    else:
        print("Cannot run test client without Envoy protobuf definitions")

    channel.close()


# ============================================================================
# Configuration from environment
# ============================================================================

def load_config_from_env() -> dict:
    """Load configuration from environment variables."""
    import os

    return {
        "port": int(os.environ.get("EXT_AUTHZ_PORT", "50051")),
        "max_workers": int(os.environ.get("EXT_AUTHZ_MAX_WORKERS", "10")),
        "log_level": os.environ.get("EXT_AUTHZ_LOG_LEVEL", "INFO"),
        "tls_enabled": os.environ.get("EXT_AUTHZ_TLS_ENABLED", "false").lower() == "true",
        "tls_cert": os.environ.get("EXT_AUTHZ_TLS_CERT", "server.crt"),
        "tls_key": os.environ.get("EXT_AUTHZ_TLS_KEY", "server.key"),
        "tls_ca": os.environ.get("EXT_AUTHZ_TLS_CA", ""),
    }


# ============================================================================
# Main entry point
# ============================================================================

if __name__ == "__main__":
    import argparse
    import os
    import sys

    parser = argparse.ArgumentParser(
        description="Envoy External Authorization gRPC Service"
    )
    parser.add_argument(
        "--port", type=int, default=50051, help="Port to listen on (default: 50051)"
    )
    parser.add_argument(
        "--max-workers",
        type=int,
        default=10,
        help="Maximum worker threads (default: 10)",
    )
    parser.add_argument(
        "--log-level",
        default="INFO",
        choices=["DEBUG", "INFO", "WARNING", "ERROR"],
        help="Log level (default: INFO)",
    )
    parser.add_argument(
        "--test",
        action="store_true",
        help="Run test client instead of server",
    )
    parser.add_argument(
        "--test-host",
        default="localhost",
        help="Host for test client (default: localhost)",
    )

    args = parser.parse_args()

    # Configure logging level
    logging.getLogger().setLevel(getattr(logging, args.log_level))

    if args.test:
        test_client(host=args.test_host, port=args.port)
    else:
        # Load any environment-based config
        env_config = load_config_from_env()

        # CLI args override env vars
        port = args.port or env_config["port"]
        max_workers = args.max_workers or env_config["max_workers"]

        # Create policy
        policy = AuthorizationPolicy()

        # Start server
        serve(port=port, max_workers=max_workers, policy=policy)